import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as n,o,c as l,a as i,b as t,d,e as r}from"./app-01aedd85.js";const s={},h=r('<h1 id="多路召回" tabindex="-1"><a class="header-anchor" href="#多路召回" aria-hidden="true">#</a> 多路召回</h1><p>“<strong>多路召回+重排序</strong>”是RAG检索层的核心优化策略，本质是“多渠道获取检索结果，再通过模型筛选最优结果”，解决单一召回通道的局限性；多路召回指通过多个不同的召回通道（向量、关键词、知识图谱），分别获取与用户查询相关的结果；重排序指将多个通道的结果合并，通过模型对结果进行打分排序，筛选出最贴合用户需求的TopN结果，作为大模型的输入。</p><h3 id="一、为什么需要多路召回" tabindex="-1"><a class="header-anchor" href="#一、为什么需要多路召回" aria-hidden="true">#</a> 一、为什么需要多路召回</h3><p>单一召回通道存在明显缺陷：</p><ul><li>向量召回擅长语义匹配，但对专业术语、关键词的精准匹配不足；</li><li>关键词召回擅长精准匹配专业术语，但无法捕捉语义相似性；</li><li>知识图谱召回擅长实体关联检索，但对非结构化文本的适配性弱。</li></ul><p>若仅用单一通道，会导致检索召回率低、结果不精准；重排序能整合多通道优势，过滤无关结果，提升检索精度，为大模型生成提供高质量上下文。</p><h3 id="二、召回通道设计" tabindex="-1"><a class="header-anchor" href="#二、召回通道设计" aria-hidden="true">#</a> 二、召回通道设计</h3><ol><li><p><strong>向量召回通道</strong>（核心通道）：<br> 实现逻辑：基于微调后的Embedding模型（如BGE），将用户查询转换为向量，在向量数据库（Milvus/Faiss）中检索相似文本片段，获取Top20结果；适配场景：非结构化文本、语义相似性查询（如“如何优化RAG检索精度”）；</p></li><li><p><strong>关键词召回通道</strong>（补充通道）：</p><ul><li>稀疏向量（Sparse Vector / Keyword）召回：使用如 BM25 等传统信息检索算法，通过关键词匹配和词频来计算文档相关性。</li><li>实现逻辑：基于Elasticsearch，对文档进行关键词索引，提取用户查询中的核心关键词（如专业术语、核心名词），进行精准匹配，获取Top10结果；</li></ul></li><li><p><strong>知识图谱召回通道</strong>（增强通道）：</p></li></ol><ul><li>基于Neo4j知识图谱，提取用户查询中的核心实体，检索与该实体相关的知识三元组（实体-关系-实体）再关联对应的文档片段，获取Top10结果；</li><li>适配场景：实体关联查询、多知识点关联查询（如“半导体芯片与测试方法的关联”）；</li></ul><h4 id="一、bm25关键字召回的实现" tabindex="-1"><a class="header-anchor" href="#一、bm25关键字召回的实现" aria-hidden="true">#</a> 一、BM25关键字召回的实现</h4>',10),g={href:"https://zhida.zhihu.com/search?content_id=237090732&content_type=Article&match_order=1&q=%E9%80%86%E6%96%87%E6%A1%A3%E9%A2%91%E7%8E%87&zhida_source=entity",target:"_blank",rel:"noopener noreferrer"},p=r('<p>我们先看下<strong>TF-IDF</strong>算法</p><p><strong>TF-IDF（term frequency–inverse document frequency，词频-逆向文件频率）<strong>是一种用于信息检索（information retrieval）与文本挖掘（text mining）的常用</strong>加权技术</strong>。</p><figure><img src="https://i-blog.csdnimg.cn/blog_migrate/a08ae69bb765ac079f53b8967a7cc119.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>**词频（TF）**<strong>表示词条（关键字）在文本中出现的频率</strong>。</p><figure><img src="https://i-blog.csdnimg.cn/blog_migrate/8aee8c29fb2c9263a4af7eb7a91e7b8c.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p><strong>IDF是逆向文档频率(Inverse Document Frequency)</strong></p><figure><img src="https://i-blog.csdnimg.cn/blog_migrate/411c0ccae911cab9c24a2255ad5de264.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p><strong>词频 (f(qi, D))</strong>: 这是查询中的词 q_i在文档 D 中出现的频率。词频是衡量一个词在文档中重要性的基本指标。词频越高，这个词在文档中的重要性通常越大。</p><figure><img src="https://pic1.zhimg.com/v2-9081c35c3675d25f997e04e2619ce6ee_1440w.jpg" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p><strong>逆文档频率 (IDF(qi))</strong>: 逆文档频率是衡量一个词对于整个文档集合的独特性或信息量的指标。它是由整个文档集合中包含该词的文档数量决定的。一个词在很多文档中出现，其IDF值就会低，反之则高。这意味着罕见的词通常有更高的IDF值，从而在相关性评分中拥有更大的权重。</p><p><strong>文档长度 (|D|)</strong>: 这是文档D 中的词汇数量。文档长度用于调整词频的影响，因为较长的文档可能仅因为它们的长度就有更高的词频。</p><p><strong>平均文档长度 (avgdl)</strong>: 这是整个文档集合中所有文档长度的平均值。它用于标准化不同文档的长度，以便可以公平比较不同长度的文档。</p><h4 id="二、bm25模型的问题" tabindex="-1"><a class="header-anchor" href="#二、bm25模型的问题" aria-hidden="true">#</a> 二、BM25模型的问题</h4><ul><li><p>BM25 基于**词频（TF）**和**逆文档频率（IDF）*<em>进行统计匹配，完全不考虑词与词之间的*<em>语义关系</em></em>。</p></li><li><p>无法处理词汇的多样性。查询 “跑”，文档中出现 “跑步”、“奔跑”，BM25 视为不同词汇。短句中的否定词（如 “不是”、“无”）会彻底反转句子含义，但 BM25 仅简单计数，无法理解逻辑。</p></li><li><p><strong>多语言与跨语言表现不佳</strong>，中文提问，英文回答不会</p></li></ul><h4 id="三、bm25模型的替代——bge-m3稀疏向量" tabindex="-1"><a class="header-anchor" href="#三、bm25模型的替代——bge-m3稀疏向量" aria-hidden="true">#</a> 三、BM25模型的替代——BGE-M3稀疏向量</h4><p>BGE-M3 的稀疏向量（Sparse Embedding）是一种 “可学习、上下文感知、带语义的关键词权重向量”，本质上是 BM25 的智能升级版；在绝大多数 RAG 场景中，它可以替代 BM25，且效果更好。</p><p><strong>形式</strong>：字典 <code>{token_id: weight, ...}</code>，大部分为 0，仅少量非零</p><h5 id="生成方式" tabindex="-1"><a class="header-anchor" href="#生成方式" aria-hidden="true">#</a> <strong>生成方式</strong></h5><ol><li>Transformer 编码得到上下文 token 向量</li><li>加线性层计算每个 token 的重要度</li><li>ReLU 过滤掉不重要项（≤0 置 0）</li><li>输出稀疏权重分布</li></ol><h5 id="与-bm25-的本质区别" tabindex="-1"><a class="header-anchor" href="#与-bm25-的本质区别" aria-hidden="true">#</a> 与 BM25 的本质区别</h5><ul><li><strong>BM25</strong>：人工规则（TF-IDF + 长度归一）、<strong>无上下文、无语义</strong></li><li><strong>BGE-M3 稀疏</strong>：<strong>神经网络学习权重、上下文感知、带弱语义</strong><ul><li>能理解 “刹车 / 制动系统”“手机 / 移动电话” 的关联</li><li>否定词、虚词权重自动压低</li><li>多语言 / 跨语言权重可迁移</li></ul></li></ul><h3 id="三、结果融合逻辑" tabindex="-1"><a class="header-anchor" href="#三、结果融合逻辑" aria-hidden="true">#</a> 三、结果融合逻辑</h3><h4 id="方式一-固定权重" tabindex="-1"><a class="header-anchor" href="#方式一-固定权重" aria-hidden="true">#</a> 方式一：固定权重</h4><ol><li>去重处理：对三个通道的结果进行去重（基于文档ID+文本片段哈希），避免重复结果进入重排序环节；</li><li>初步筛选：过滤无效结果（如文本长度＜50字、与查询意图不符的结果）；</li><li>权重分配：为三个通道的结果分配不同权重（向量召回0.6、关键词召回0.25、知识图谱召回0.15），权重可根据实际检索效果迭代调整。</li></ol><p>问题：<strong>如果在召回阶段某一路的文档召回质量不好如何调整</strong></p><p>召回质量分为</p><ul><li>召回数量（太少说明该路不准确）</li><li>召回的分数差距大，获取前n个分数高的数据</li><li>召回的实体是否准确</li></ul><h4 id="方式一、分别对于三路召回进行归一化分数统计-重排序分数取topn" tabindex="-1"><a class="header-anchor" href="#方式一、分别对于三路召回进行归一化分数统计-重排序分数取topn" aria-hidden="true">#</a> 方式一、分别对于三路召回进行归一化分数统计（重排序分数取TopN）</h4><p>分别对于三路召回的数据进行重排序，检查每路召回的数据重排序的分数，获取总体分数大于阈值的条数</p><h4 id="方式二、根据召回数量调整权重" tabindex="-1"><a class="header-anchor" href="#方式二、根据召回数量调整权重" aria-hidden="true">#</a> 方式二、根据<strong>召回数量</strong>调整权重</h4><ul><li><p>Nv：向量召回文档数</p></li><li><p>Nk：关键词召回数</p></li><li><p>Ng：图谱召回数</p></li></ul><h4 id="方式三、根据召回的分数质量动态调整" tabindex="-1"><a class="header-anchor" href="#方式三、根据召回的分数质量动态调整" aria-hidden="true">#</a> 方式三、根据召回的分数质量动态调整</h4><p>先对召回的文档数据进行分数归一化</p><ul><li><p>向量：cos 相似度本身 ∈ [0,1]</p></li><li><p>关键词：min-max 归一化</p></li><li><p>知识图谱：路径得分 / 实体关联度归一化</p><ul><li>路径长度得分（最常用），路径越短，关联越强</li><li>路径置信度 / 权重乘积</li></ul></li></ul><p>向量召回分数<strong>差距很大</strong>（top1 远高于其他）→ 说明语义非常聚焦，<strong>提高向量权重</strong></p><p>向量分数<strong>很平、都差不多</strong>→ 语义模糊，<strong>降低向量权重，提高关键词</strong></p><p>计算该路召回分数的<strong>方差</strong></p><ul><li>方差大 → 可信度高 → 权重 + 0.1</li><li>方差小 → 可信度低 → 权重 - 0.1</li></ul><h4 id="方式四-根据问题类型自动分配-最实用" tabindex="-1"><a class="header-anchor" href="#方式四-根据问题类型自动分配-最实用" aria-hidden="true">#</a> 方式四：根据<strong>问题类型</strong>自动分配（最实用）</h4><table><thead><tr><th>Query 类型</th><th>向量权重</th><th>关键词权重</th><th>图谱权重</th><th>典型场景</th></tr></thead><tbody><tr><td>语义泛化 / 开放式问题</td><td>0.6</td><td>0.2</td><td>0.2</td><td>怎么办、如何理解、解释</td></tr><tr><td>精确关键词 / 术语查询</td><td>0.3</td><td>0.5</td><td>0.2</td><td>定义、公式、参数</td></tr><tr><td>实体 / 关系 / 事实类问题</td><td>0.4</td><td>0.2</td><td>0.4</td><td>谁、什么、关系、原因</td></tr><tr><td>图谱无召回</td><td>0.6</td><td>0.3</td><td>0.1</td><td>普通段落问答</td></tr></tbody></table><p>知识图谱权重最高给到 0.4 就够，再高容易引入噪声</p><h3 id="四、重排序模型的选择" tabindex="-1"><a class="header-anchor" href="#四、重排序模型的选择" aria-hidden="true">#</a> 四、重排序模型的选择</h3><p>模型对比与选型：</p><ul><li><strong>CrossEncoder</strong>：基于Transformer架构，通过输入“查询+文本片段”的对，计算相似度得分，精度高、适配性强，但推理速度较慢，适合中小规模结果重排序（Top50以内）；</li><li><strong>Reranker</strong>（如Cohere Reranker、BAAI-Reranker）：轻量级重排序模型，推理速度快，精度略低于CrossEncoder，适合大规模结果重排序（Top100以内）；</li><li>选型策略：项目中采用“CrossEncoder为主、Reranker为辅”，小批量结果（Top50）用CrossEncoder保证精度，大批量结果（Top100）用Reranker保证速度。</li></ul><p>用领域专属数据（如半导体文档）微调CrossEncoder模型，优化专业术语的相似度计算；</p><p>重排序特征：<strong>除了“查询-文本相似度”，额外引入“通道权重、文本相关性、实体关联度”三个特征</strong>，综合打分排序；</p><p>注意点：</p><ol><li>召回通道的权重需根据实际检索效果迭代调整，避免某一通道权重过高导致结果偏差；</li><li>重排序模型需做领域微调，否则无法适配专业场景的语义需求；</li><li>控制各通道的召回数量，避免结果过多导致重排序延迟增加；</li><li>知识图谱召回需保证知识图谱的准确性和完整性，否则会引入错误结果。</li></ol>',48);function c(u,m){const e=n("ExternalLinkIcon");return o(),l("div",null,[h,i("p",null,[t("BM25的核心思想是基于词频(TF)和"),i("a",g,[t("逆文档频率"),d(e)]),t("(IDF)来,同时还引入了文档的长度信息来计算文档D和查询Q之间的相关性。")]),p])}const _=a(s,[["render",c],["__file","22、多路召回.html.vue"]]);export{_ as default};
